import re
with open('03_计算机组成原理/计算机组成原理_截图整理笔记.md', 'r', encoding='utf-8') as f:
    lines = f.readlines()

print("=== Final sweep: Chapters 1-2 remaining backtick patterns ===")
for i, line in enumerate(lines[50:780], 51):
    ticks = re.findall(r'`([^`]+)`', line.strip())
    for t in ticks:
        if len(t) > 80:
            continue
        # Check for formula indicators
        has_math = False
        indicators = ['=', '⊕', '·', '~', '÷', '×', '补', '原', '反', '移']
        for ind in indicators:
            if ind in t:
                has_math = True
                break
        # Check for exponent: ^ followed by digit
        if re.search(r'\^\d', t):
            has_math = True
        if has_math:
            # Skip known non-formula items
            skip = False
            for kw in ['0x', '辅助位', 'P = 0, Y-1', 'P:Y']:
                if t.startswith(kw) or kw in t:
                    skip = True
            # Skip code/assembly/register patterns
            for kw in ['jmp', 'je', 'jg', 'jl', 'jne', 'jge', 'jle', 'cmp', 'add', 'PC', 'IR', 'MAR']:
                if kw in t.lower()[:10]:
                    skip = True
            if not skip:
                print(f"  Line {i}: `{t}`")

print("\n=== Verify $$ blocks are balanced ===")
in_block = False
block_start = 0
for i, line in enumerate(lines, 1):
    if line.strip() == '$$':
        if not in_block:
            in_block = True
            block_start = i
        else:
            in_block = False
if in_block:
    print(f"  WARNING: Unclosed $$ block starting at line {block_start}")
else:
    print("  All $$ blocks balanced")

print("\n=== Final spot check of key formulas ===")
checks = [
    ('CPU time formula', r'\\text\{CPU 执行时间\} = \\text\{指令条数\}'),
    ('ALU formula', r'S_i = A_i \\oplus B_i \\oplus'),
    ('MIPS formula', r'\\text\{MIPS\} = \\text\{主频\}'),
    ('IEEE formula', r'\\text\{数值\} = \(-1\)'),
    ('Hamming formula', r'2\^r \\geq k \+ r \+ 1'),
    ('Cla formula', r'G_i = A_i \\cdot B_i'),
    ('Parity formula', r'D_1 \\oplus D_2 \\oplus'),
]
for name, pattern in checks:
    found = False
    for i, line in enumerate(lines, 1):
        if re.search(pattern, line):
            found = True
            break
    status = 'OK' if found else 'MISSING'
    print(f"  {name}: {status}")
